sql:
SELECT city_name, state, tourism_index
FROM cities
WHERE tourism_index > (SELECT AVG(tourism_index) FROM cities);

SELECT weather_id, analysis_result
FROM diner_analysis
WHERE weather_id > 5;

SELECT city_name, average_income
FROM cities
WHERE tourism_index >= 8;

SELECT location_name, average_price
FROM dining_locations
WHERE type = 'fast food';

external_knowledge:
- Warm weather conditions are generally considered to start at 70°F;
- Early summer days refer to the period from June 1 to June 30;
- Diner reviews are based on the average diner rating;
- The "best" diner reviews indicate the highest average diner ratings.
